<template><main><header><p>GridVerse</p><h1>Common Network Model</h1></header><section class="panel"><h2>CGMES upload</h2><p>Upload RDF/XML or ZIP packages. Files are validated and stored before downstream parsing.</p><input type="file" accept=".zip,.xml,.rdf" @change="pick"/><GvButton :disabled="!file||busy" @click="submit">{{busy?'Uploading…':'Upload model'}}</GvButton><progress v-if="busy||progress" :value="progress" max="100"/><StatusBadge v-if="status" :state="status.importStatus.state"/><p v-if="status">Network ID: <code>{{status.network.networkId}}</code></p><p v-if="error" class="error">{{error}}</p></section></main></template>
<script setup lang="ts">import{ref}from'vue';import{GvButton,StatusBadge}from'@gridverse/gui.common/src';import{uploadModel}from'./services/cnmApi';const file=ref<File>();const busy=ref(false),progress=ref(0),status=ref<any>(),error=ref('');function pick(e:Event){file.value=(e.target as HTMLInputElement).files?.[0]}async function submit(){if(!file.value)return;busy.value=true;error.value='';try{status.value=await uploadModel(file.value,v=>progress.value=v)}catch(e){error.value=String(e)}finally{busy.value=false}}</script>
<style scoped>main{max-width:900px;margin:auto;padding:2rem}header p{color:#087e8b;font-weight:800}.panel{background:white;border-radius:12px;padding:2rem;display:grid;gap:1rem;box-shadow:0 8px 28px #17324d18}.error{color:#b42318}progress{width:100%}</style>
